-- Neymar Jr Archive + Supabase
-- Cole este arquivo no SQL Editor do Supabase e execute.
-- Ele cria as tabelas, habilita RLS e popula os dados iniciais do site.

create extension if not exists pgcrypto;

create table if not exists public.neymar_profile (
  id smallint primary key default 1,
  name text not null,
  short_name text,
  birth text,
  birthplace text,
  position text,
  height text,
  dominant_foot text,
  hero_image text,
  subtitle text,
  updated_at_label text,
  updated_at timestamptz default now()
);

create table if not exists public.neymar_totals (
  id bigint generated by default as identity primary key,
  sort_order int default 0,
  label text not null,
  value numeric not null,
  suffix text default '',
  note text
);

create table if not exists public.neymar_goal_types (
  id bigint generated by default as identity primary key,
  sort_order int default 0,
  type text not null,
  value numeric not null,
  source text,
  description text
);

create table if not exists public.neymar_club_passages (
  id bigint generated by default as identity primary key,
  sort_order int default 0,
  slug text unique,
  club text not null,
  period text,
  country text,
  role text,
  shirt text,
  image text,
  summary text,
  games int default 0,
  goals int default 0,
  assists int default 0,
  penalties int default 0,
  free_kicks int default 0,
  highlights jsonb default '[]'::jsonb,
  titles jsonb default '[]'::jsonb,
  important_games jsonb default '[]'::jsonb
);

create table if not exists public.neymar_national_teams (
  id bigint generated by default as identity primary key,
  sort_order int default 0,
  team text not null,
  period text,
  games int default 0,
  goals int default 0,
  titles jsonb default '[]'::jsonb,
  note text
);

create table if not exists public.neymar_collective_titles (
  id bigint generated by default as identity primary key,
  sort_order int default 0,
  category text not null,
  title text not null,
  years text,
  image text
);

create table if not exists public.neymar_individual_awards (
  id bigint generated by default as identity primary key,
  sort_order int default 0,
  classification text not null,
  title text not null,
  years text,
  image text,
  detail text
);

create table if not exists public.neymar_important_goals (
  id bigint generated by default as identity primary key,
  sort_order int default 0,
  classification text,
  competition text,
  type text,
  opponent text,
  date_label text,
  detail text
);

create table if not exists public.neymar_opponents (
  id bigint generated by default as identity primary key,
  sort_order int default 0,
  name text not null,
  category text,
  context text,
  goals int default 0
);

create table if not exists public.neymar_gallery (
  id bigint generated by default as identity primary key,
  sort_order int default 0,
  title text not null,
  tag text,
  image text,
  credit text
);

create table if not exists public.neymar_sources (
  id bigint generated by default as identity primary key,
  sort_order int default 0,
  label text not null,
  url text not null
);

create table if not exists public.site_feedback (
  id uuid primary key default gen_random_uuid(),
  created_at timestamptz default now(),
  name text,
  email text,
  category text,
  source_url text,
  message text not null,
  page text,
  path text,
  status text default 'novo'
);

create table if not exists public.site_page_views (
  id uuid primary key default gen_random_uuid(),
  created_at timestamptz default now(),
  page text,
  path text,
  referrer text,
  user_agent text
);

-- RLS: leitura pública apenas das tabelas de conteúdo.

alter table public.neymar_profile enable row level security;
drop policy if exists "Public read neymar_profile" on public.neymar_profile;
create policy "Public read neymar_profile" on public.neymar_profile for select to anon, authenticated using (true);

alter table public.neymar_totals enable row level security;
drop policy if exists "Public read neymar_totals" on public.neymar_totals;
create policy "Public read neymar_totals" on public.neymar_totals for select to anon, authenticated using (true);

alter table public.neymar_goal_types enable row level security;
drop policy if exists "Public read neymar_goal_types" on public.neymar_goal_types;
create policy "Public read neymar_goal_types" on public.neymar_goal_types for select to anon, authenticated using (true);

alter table public.neymar_club_passages enable row level security;
drop policy if exists "Public read neymar_club_passages" on public.neymar_club_passages;
create policy "Public read neymar_club_passages" on public.neymar_club_passages for select to anon, authenticated using (true);

alter table public.neymar_national_teams enable row level security;
drop policy if exists "Public read neymar_national_teams" on public.neymar_national_teams;
create policy "Public read neymar_national_teams" on public.neymar_national_teams for select to anon, authenticated using (true);

alter table public.neymar_collective_titles enable row level security;
drop policy if exists "Public read neymar_collective_titles" on public.neymar_collective_titles;
create policy "Public read neymar_collective_titles" on public.neymar_collective_titles for select to anon, authenticated using (true);

alter table public.neymar_individual_awards enable row level security;
drop policy if exists "Public read neymar_individual_awards" on public.neymar_individual_awards;
create policy "Public read neymar_individual_awards" on public.neymar_individual_awards for select to anon, authenticated using (true);

alter table public.neymar_important_goals enable row level security;
drop policy if exists "Public read neymar_important_goals" on public.neymar_important_goals;
create policy "Public read neymar_important_goals" on public.neymar_important_goals for select to anon, authenticated using (true);

alter table public.neymar_opponents enable row level security;
drop policy if exists "Public read neymar_opponents" on public.neymar_opponents;
create policy "Public read neymar_opponents" on public.neymar_opponents for select to anon, authenticated using (true);

alter table public.neymar_gallery enable row level security;
drop policy if exists "Public read neymar_gallery" on public.neymar_gallery;
create policy "Public read neymar_gallery" on public.neymar_gallery for select to anon, authenticated using (true);

alter table public.neymar_sources enable row level security;
drop policy if exists "Public read neymar_sources" on public.neymar_sources;
create policy "Public read neymar_sources" on public.neymar_sources for select to anon, authenticated using (true);

alter table public.site_feedback enable row level security;
alter table public.site_page_views enable row level security;
drop policy if exists "Public insert site_feedback" on public.site_feedback;
create policy "Public insert site_feedback" on public.site_feedback for insert to anon, authenticated with check (true);
drop policy if exists "Public insert site_page_views" on public.site_page_views;
create policy "Public insert site_page_views" on public.site_page_views for insert to anon, authenticated with check (true);

-- Dados iniciais. Se rodar novamente, as tabelas de conteúdo são recarregadas.
truncate table public.neymar_profile, public.neymar_totals, public.neymar_goal_types, public.neymar_club_passages, public.neymar_national_teams, public.neymar_collective_titles, public.neymar_individual_awards, public.neymar_important_goals, public.neymar_opponents, public.neymar_gallery, public.neymar_sources restart identity cascade;

