insert into public.neymar_club_passages (sort_order,slug,club,period,country,role,shirt,image,summary,games,goals,assists,penalties,free_kicks,highlights,titles,important_games) values (1,'santos-1','Santos FC','2009–2013','Brasil','Revelação, protagonista e campeão continental','11','https://commons.wikimedia.org/wiki/Special:FilePath/Neymar%20Junior%20the%20Future%20of%20Brazil%202.jpg','Surgiu como fenômeno no Santos, decidiu mata-matas, liderou geração campeã da Libertadores e consolidou-se como maior promessa brasileira do período.',225,136,64,20,4,'["Estreia profissional em 2009.", "Campeão da Copa do Brasil 2010 com artilharia da competição.", "Campeão da Libertadores 2011, encerrando jejum histórico do Santos.", "Gol que venceu o Prêmio Puskás 2011 contra o Flamengo.", "Eleito melhor jogador sul-americano em 2011 e 2012."]'::jsonb,'["Campeonato Paulista 2010, 2011 e 2012", "Copa do Brasil 2010", "Copa Libertadores 2011", "Recopa Sul-Americana 2012"]'::jsonb,'[{"date": "27/07/2011", "title": "Santos x Flamengo", "detail": "Gol antológico que rendeu o FIFA Puskás Award de 2011."}, {"date": "22/06/2011", "title": "Santos x Peñarol", "detail": "Final da Libertadores 2011; Neymar marcou na decisão."}, {"date": "2010", "title": "Copa do Brasil", "detail": "Artilheiro com 11 gols e campeão nacional."}]'::jsonb);
insert into public.neymar_club_passages (sort_order,slug,club,period,country,role,shirt,image,summary,games,goals,assists,penalties,free_kicks,highlights,titles,important_games) values (2,'barcelona','FC Barcelona','2013–2017','Espanha','Trio MSN, auge europeu e Champions League','11','https://commons.wikimedia.org/wiki/Special:FilePath/Neymar%20-%20FC%20Barcelona%20-%202015.jpg','No Barcelona, Neymar viveu seu auge europeu. Formou o trio MSN com Messi e Suárez, venceu a Champions e decidiu jogos gigantes.',186,105,76,10,5,'["Chegada oficial em 2013 e adaptação ao futebol europeu.", "Temporada 2014/15 histórica com Champions, La Liga e Copa do Rei.", "Artilheiro da Champions 2014/15 ao lado de Messi e Cristiano Ronaldo, com 10 gols.", "Gol na final da Champions contra a Juventus em Berlim.", "Protagonista da remontada contra o PSG em 2017."]'::jsonb,'["La Liga 2014/15 e 2015/16", "Copa do Rei 2014/15, 2015/16 e 2016/17", "Champions League 2014/15", "Mundial de Clubes 2015", "Supercopa da Espanha 2013"]'::jsonb,'[{"date": "06/06/2015", "title": "Barcelona 3 x 1 Juventus", "detail": "Gol no fim da final da Champions League 2014/15."}, {"date": "08/03/2017", "title": "Barcelona 6 x 1 PSG", "detail": "Dois gols e uma assistência na remontada histórica."}, {"date": "21/04/2015", "title": "Barcelona x PSG", "detail": "Dois gols nas quartas da Champions."}]'::jsonb);
insert into public.neymar_club_passages (sort_order,slug,club,period,country,role,shirt,image,summary,games,goals,assists,penalties,free_kicks,highlights,titles,important_games) values (3,'psg','Paris Saint-Germain','2017–2023','França','Transferência recorde, camisa 10 e final europeia','10','https://commons.wikimedia.org/wiki/Special:FilePath/Neymar%20PSG.jpg','Contratação mais cara da história, Neymar levou criatividade e decisão ao PSG, conquistou títulos nacionais e chegou à final da Champions em 2020.',173,118,77,24,7,'["Transferência recorde mundial em 2017.", "Eleito melhor jogador da Ligue 1 em 2017/18.", "Conduziu o PSG à primeira final de Champions League do clube em 2020.", "Passou dos 100 gols pelo PSG.", "Quarto maior artilheiro da história do clube no período."]'::jsonb,'["Ligue 1 2017/18, 2018/19, 2019/20, 2021/22 e 2022/23", "Copa da França 2017/18, 2019/20 e 2020/21", "Copa da Liga Francesa 2017/18 e 2019/20", "Supercopa da França 2018, 2020 e 2022"]'::jsonb,'[{"date": "2020", "title": "PSG na final da Champions", "detail": "Participação central na campanha europeia histórica do clube."}, {"date": "02/12/2020", "title": "Manchester United x PSG", "detail": "Atuação decisiva com gols em Old Trafford."}, {"date": "2018", "title": "Primeira temporada", "detail": "Temporada de impacto com título francês e prêmio de jogador do ano."}]'::jsonb);
insert into public.neymar_club_passages (sort_order,slug,club,period,country,role,shirt,image,summary,games,goals,assists,penalties,free_kicks,highlights,titles,important_games) values (4,'alhilal','Al-Hilal SFC','2023–2025','Arábia Saudita','Projeto saudita e título nacional','10','https://commons.wikimedia.org/wiki/Special:FilePath/Neymar%20Al-Hilal%20SFC%202023.jpg','Passagem marcada por alta expectativa, lesão grave e participação reduzida. Ainda assim, integrou elenco campeão saudita.',7,1,3,0,0,'["Chegada ao futebol saudita em 2023.", "Primeiro gol pelo clube em competição asiática.", "Campeão saudita 2023/24 com o Al-Hilal.", "Lesão no joelho reduziu drasticamente sua sequência."]'::jsonb,'["Saudi Pro League 2023/24"]'::jsonb,'[{"date": "03/10/2023", "title": "Al-Hilal x Nassaji", "detail": "Primeiro gol pelo Al-Hilal."}]'::jsonb);
insert into public.neymar_club_passages (sort_order,slug,club,period,country,role,shirt,image,summary,games,goals,assists,penalties,free_kicks,highlights,titles,important_games) values (5,'santos-2','Santos FC','2025–atual','Brasil','Retorno ao clube formador','10','https://commons.wikimedia.org/wiki/Special:FilePath/Neymar%20Barcelona%20presentation%202.jpg','Retorno ao Santos com status de ídolo máximo contemporâneo, assumindo camisa 10 e função de liderança técnica.',36,15,8,6,1,'["Retorno anunciado após ciclo no exterior.", "Camisa 10 e referência técnica do elenco.", "Nova fase com foco em liderança, protagonismo e recuperação de ritmo."]'::jsonb,'[]'::jsonb,'[{"date": "2025", "title": "Volta à Vila Belmiro", "detail": "Retorno simbólico ao clube que o revelou."}]'::jsonb);
